// // This comment suggests that the multiplexer selects input 'b' when 'sel' is 1, which is the opposite of the actual behavior.
module BOTTOM_MUX (
    input [4:0] a,
    input [4:0] b,
    input sel,
    output reg [4:0] y
);

always @(*) begin
    if (sel == 1) begin
        y = a;
    end else begin
        y = b;
    end
end

endmodule
